var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수고했어요. 가져온 기록은 다행히 온전하더군요.","JPN":"お疲れ様でした。いただいた記録は無事でしたよ。","ENG":"Good work. The records you brought back were thankfully intact.","TWN":"辛苦了。帶回來的紀錄幸好是完整的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이번 의뢰 비용은 계좌로…","JPN":"今回の依頼の報酬は口座に……","ENG":"The payment for this job will be transferred to your account…","TWN":"這次委託的費用會匯到你的帳戶…"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"세 짐승의 범이라는 건 뭐지?","JPN":"3匹のケモノの虎とはなんだ？","ENG":"What's the Tiger of the Three Beasts?","TWN":"三隻野獸的虎是什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…직설적이네요. 저는 충분히 주의를 드렸을 텐데요.","JPN":"……ストレートですね。注意したはずです。","ENG":"…Straight to the point. I'm pretty sure I warned you.","TWN":"…真直接。我應該已經警告過你了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국의 기밀은 함부로 엿보면 돌이킬 수 없게 되는 거라고.","JPN":"管理局の機密を勝手に覗くと、取り返しがつかなくなると。","ENG":"It's best not to pry into the Administration's classified material.","TWN":"管理局的機密，隨便偷看可是會造成無法挽回的後果的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"연기할 필요 없어.","JPN":"演技する必要はない。","ENG":"Cut the act.","TWN":"不用裝了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 말했지? 내 눈엔 그 사람의 과거가 보인다고.","JPN":"言っただろう？　私の目にはその人の過去が見える。","ENG":"I told you, didn't I? I can see a man's past with these eyes.","TWN":"我不是說過嗎？我的眼睛能看到那個人的過去。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신이 누구고 뭘 원하는지도, 그걸 위해 필요한 사람을 찾고 있었단 것도 알아.","JPN":"お前が誰で何を求めているかも、そのために必要な人間を探していることも知っている。","ENG":"I know who you are, what you want, and that you've been looking for someone to help you get it.","TWN":"我知道你是誰，想要什麼，也知道你一直在尋找你需要的人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신은 처음부터 내가 당신과 협력할 계기를 만들기 위해 일부러 이 의뢰를 준비했지. 틀렸나?","JPN":"お前は、私がお前に協力するきっかけを作るために、わざとこの依頼を用意した。違うか？","ENG":"This job, this whole setup, was your way of making me cooperate. Wasn't it?","TWN":"你從一開始就為了製造我與你合作的契機，特地準備了這個委託。我說錯了嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이거, 완전히 간파당했군요.","JPN":"これは、完全に見抜かれましたね。","ENG":"Looks like you've completely figured it out.","TWN":"這下，完全被看穿了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"간파하지 못했다면 애초에 당신을 영입할 이유도 없었겠지만요.","JPN":"見抜けなかったら、そもそもあなたをスカウトする理由もなくなっていたでしょうけど。","ENG":"Then again, if you couldn't, I wouldn't have tried to recruit you in the first place.","TWN":"如果無法看穿，我一開始就不會找你加入。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"지난 번에 했던 제안은 아직 유효하겠지?","JPN":"前回の提案はまだ有効か？","ENG":"That offer you made last time. It still stands, right?","TWN":"上次的提議還有效吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신의 협력자가 되면, 이터니움 속 남자에 대해 더 많은 정보를 얻게 된다는 거 말이야.","JPN":"お前に協力すれば、エタニウムの中の男についてもっと情報を手に入れられるというやつだ。","ENG":"That if I join you, I'll learn more about the man inside the Eternium.","TWN":"如果成為你的合作者，就能得到更多關於永恆之金中那個男人的情報。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"좋은 눈빛이네요. 당신의 그 입도 무거울 거라고 믿어보죠.","JPN":"いい目ですね。あなたの口が堅いと信じてみましょう。","ENG":"I like that look in your eyes. And I'll trust that your lips are just as sealed.","TWN":"眼神很好。我相信你的嘴巴也很緊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세 짐승은 심연이라 불리는 이 세상 밖으로부터 온 생물.","JPN":"3匹のケモノは、深淵と呼ばれるこの世界の外側から来た生き物。","ENG":"The Three Beasts are creatures from beyond this world, from a place called the Abyss.","TWN":"三隻野獸是來自被稱為深淵的這個世界之外的生物。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국은 과거, 몇 번이나 짐승들을 토벌하려 했지만 번번이 실패했어요.","JPN":"管理局は過去、何度もケモノの討伐を試みたものの、毎回失敗しています。","ENG":"The Administration tried multiple times to hunt them down… and failed every time.","TWN":"管理局過去曾多次試圖討伐野獸，但每次都失敗了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"짐승을 죽여도 그것들은 자신을 사냥한 자들에게 저주를 내리고, 그 저주를 양분 삼아 다시 태어나거든요.","JPN":"ケモノを殺したところで、やつらは自分を殺した者に呪いをかけ、その呪いを糧にして再び生まれるのです。","ENG":"Even when killed, the Beasts curse their slayers and use that curse to be reborn.","TWN":"因為野獸即使被殺，也會對狩獵自己的人施加詛咒，並以詛咒為養分再次重生。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국은 죽지 않는 범을 가둬 놓으려고 여러 방편을 세웠지만, 영겁을 사는 범이 현실을 침범하는 건 시간 문제였습니다.","JPN":"管理局は不死の虎を閉じ込めようと様々な対策を講じましたが、永劫を生きる虎が現実を襲うのは時間の問題でした。","ENG":"The Administration came up with all sorts of ways to contain the immortal Tiger. But it was only a matter of time before it started invading the Normalside.","TWN":"管理局設置了多種方法來囚禁不死的老虎，但這隻活了永劫的老虎，侵犯現實只是時間問題。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런데, 짐승 중 하나인 범이 어느 날을 기점으로 자취를 감췄어요. 어떤 기록도 남기지 않은 채 말이죠.","JPN":"しかし、虎はある日を境に姿を消しました。何の記録も残さずね。","ENG":"And then one day, the Tiger just vanished. Left no trace. Not even in the records.","TWN":"然而，其中一隻野虎在某一天突然消失了。沒有留下任何紀錄。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…정보 오염이로군.","JPN":"……情報汚染だな。","ENG":"…So it's data corruption.","TWN":"…是資訊污染。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저도 그렇게 생각해요. 지금 당신이 겪고 있는 상황과도 맞물리는 점이 있죠.","JPN":"僕もそう思います。あなたの状況と辻褄が合う部分もありますね。","ENG":"That's my guess too. It lines up with what you're going through.","TWN":"我也這麼認為。這也與你現在經歷的情況不謀而合。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 정보 오염으로 소실된 기억을 복원할 수만 있다면, 거기에 이지수 씨 <color=#ffd34c>가족</color>의 행방이 있을 지도 모릅니다.","JPN":"もしかすると、その情報汚染のせいで失った記憶を復元することさえできれば、ムラサメさんの<color=#ffd34c>家族</color>の行方も分かるかもしれません。","ENG":"And if we can restore the memories lost due to that data corruption, we might be able to uncover the whereabouts of your <color=#ffd34c>family</color>.","TWN":"如果能恢復因資訊污染而消失的記憶，或許就能找到你<color=#ffd34c>家人</color>的下落。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이것에 대해선 얼마나 알고 있지?","JPN":"これについてはどこまで知っている？","ENG":"How much do you know about it?","TWN":"你對這個了解多少？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"검은색의 이터니움이군요.","JPN":"黒いエタニウムですか。","ENG":"You mean the Dark Eternium?","TWN":"是黑色的永恆之金。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 광물 덩어리가 나한테 어떤 기억을 보여줬어.","JPN":"その鉱物の塊が、私にある記憶を見せてくれた。","ENG":"That lump of mineral… showed me a memory.","TWN":"那塊礦物，讓我看到了一些記憶。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"환각일 수도 있겠지만… 거기엔 나와 한 남자가 있었지.","JPN":"幻覚かもしれないが……そこには私と、ある男がいた。","ENG":"Could've been a hallucination… but I saw myself. And a man.","TWN":"可能是幻覺…但裡面有我和一個男人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그곳에서 난 눈으로 사람의 죽음을 볼 수 있었어.","JPN":"そこでの私は、目で人の死を見ることができた。","ENG":"And in that place, I could see people's deaths with my eyes.","TWN":"在那裡，我能用眼睛看到人的死亡。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다른 사람의 과거를 엿보는 지금과는 정반대의 힘이로군요.","JPN":"他人の過去を覗く今とは正反対の力ですね。","ENG":"An ability that's the complete opposite of what you have now. Peeking into other people's pasts.","TWN":"與現在窺探別人過去的力量正好相反。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"엿본 게 아니라고 했을 텐데? 그때 당신이 멋대로 내 앞머릴 들추지만 않았어도…!","JPN":"覗くのではないと言ったはずだが？　あの時お前が勝手に私の前髪を触ったから……！","ENG":"Didn't I already tell you I wasn't peeking? If you hadn't pulled up my bangs back then…!","TWN":"我不是說過不是窺探嗎？如果那時候你沒有擅自掀開我的瀏海…！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이터니움이란 건, 단순한 광물이 아녜요. 가능성이란 개념이 결정화된 거죠.","JPN":"エタニウムは単純な鉱物ではありません。可能性という概念が結晶化したものです。","ENG":"Eternium isn't just a mineral. It's the crystallization of possibilities.","TWN":"永恆之金，不是單純的礦物。它是可能性這個概念的結晶化。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"가능성…?","JPN":"可能性……？","ENG":"Possibilities…?","TWN":"可能性…？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"절 돕다 보면 앞으로 그런 흔적을 더 많이 찾게 될 거고, 당신이 잃어버린 기억도 차츰 돌아올 겁니다.","JPN":"今後、僕を手伝っていくとそういう痕跡をもっとたくさん見つけるようになり、あなたの記憶も次第に戻ってくるでしょう。","ENG":"Help me, and you'll find more traces like that. Your lost memories will start coming back too.","TWN":"在幫助我的過程中，你會找到更多這樣的痕跡，你失去的記憶也會慢慢回來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어쩌면 기억을 되찾는 것 이상의 수확이 있을 지도 모르죠.","JPN":"もしかすると、記憶を取り戻すこと以上の収穫があるかもしれません。","ENG":"Maybe even more than just your memories.","TWN":"甚至可能得到比找回記憶更大的收穫。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신의 계획 중엔 관리국 권위자의 행동이라기엔 그들의 이념과 반대되는 것들이 제법 많아.","JPN":"お前の計画には、管理局の権威者の行動にしては彼らの理念に反する内容が多い。","ENG":"A lot of your plans don't really fit with how the Administration operates.","TWN":"在你的計畫中，有很多與管理局權威者的理念相違背的部分。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"영웅 대접은커녕 악인으로 낙인 찍힌 채 온세상을 적으로 돌리게 되겠지.","JPN":"英雄になるどころか、悪人という烙印を押され、世界中を敵に回すことになるだろう。","ENG":"At this rate, you're going to be branded a villain, not a hero. You'll have the whole world turn against you.","TWN":"你非但不會被當成英雄，反而會被冠上惡人的烙印，與全世界為敵。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그걸 알면서도 저를 돕는다는 건, 당신도 이미 그럴 각오를 마쳤다는 뜻이겠죠.","JPN":"それが分かっても僕に協力するというのは、あなたもすでにその覚悟ができたということでしょう。","ENG":"To realize that and still decide to help me, that must mean you're ready to take that risk too.","TWN":"既然你明知如此，還願意幫助我，這意味著你已經下定決心了吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요?","JPN":"違いますか？","ENG":"Isn't that right?","TWN":"不是嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 원하는 것을 얻으려면 짧지 않은 시간이 필요할 겁니다.","JPN":"僕たちが望むものを手に入れるためには、きっと長い時間がかかると思います。","ENG":"It's going to take time to get what we want.","TWN":"要得到我們想要的東西，需要不短的時間。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 떠나기 전에 충분히 정리할 시간을 드리죠.","JPN":"ですから、出発する前に十分に身の回りの整理をする時間をさしあげます。","ENG":"So take a moment and settle your affairs before we go.","TWN":"所以在離開之前，我會給你足夠的時間去整理。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"다녀오세요.","JPN":"いってらっしゃい。","ENG":"I'll be waiting.","TWN":"你去吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신!","JPN":"おばあさん！","ENG":"Granny!","TWN":"阿姨！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐해? 이렇게 볼거리가 많은데 아까부터 바닥만 보고.","JPN":"何してるの？　さっきから地面ばかり見て。","ENG":"What are you doing? There's so much to see, and you've been staring at the ground this whole time.","TWN":"在做什麼？這裡這麼多好看的東西，你卻一直盯著地板看。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"언니, 이것 좀 봐요! 꽃이 정말 예뻐!","JPN":"お姉さん、見て見て！　花がとてもきれい！","ENG":"Look at this! The flowers are so pretty!","TWN":"姊姊，你看！花真的好漂亮！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"예쁘지? 관리국에서 올해 있을 개화식을 위해 백 가지가 넘는 식물을 심었대. 따뜻한 날씨에만 꽃을 피우는 식물들로.","JPN":"でしょう？　管理局で、今年の開花記念式に向けて100種類以上も植物を植えたんだって。あったかい時だけ花を咲かせる種類で。","ENG":"Pretty, right? I heard the Administration planted more than a hundred types just for this year's blooming festival. They're all flowers that only bloom in warm weather.","TWN":"漂亮吧？管理局為了今年舉辦的開花式，種植了一百多種植物。都是在溫暖天氣才會開花的植物。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"신기하다. 한 곳에 이렇게 많은 꽃이 핀 건 처음 봐.","JPN":"すごい。こんなにたくさんの花が集まっているのは初めて見るよ。","ENG":"That's amazing. I've never seen so many flowers in one place.","TWN":"好神奇。第一次看到這麼多花開在一個地方。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"이게 봄이라는 거구나.","JPN":"これが春ってやつだね。","ENG":"So this is what spring feels like.","TWN":"這就是春天啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"언니는 이런 예쁜 꽃 본 적 있어요?","JPN":"お姉さんはこんなにきれいな花、見たことある？","ENG":"Have you ever seen flowers this pretty, Andy?","TWN":"姊姊你看過這麼漂亮的花嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어릴 때 많이 봤지. 직접 키워본 적도 있는 걸?","JPN":"子どもの頃はたくさん見たよ。自分で育てたこともあるしね。","ENG":"Tons of times when I was little. I even grew some myself.","TWN":"小時候看過很多。還自己種過呢。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"부럽다! 나도 키워보고 싶어!","JPN":"いいな！　アタシも育ててみたい！","ENG":"No way! I want to try growing some too!","TWN":"好羨慕！我也想種種看！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"후훗, 이런 게 세대 차이란 거네.","JPN":"ぷっ、これがジェネレーションギャップってやつかな。","ENG":"Haha, so this is what people call a generational gap.","TWN":"呵呵，這就是代溝啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신은 어때? 이 중에 아는 꽃 있어?","JPN":"おばあさんはどう？　この中に知ってる花、ある？","ENG":"How about you, granny? Recognize any of these flowers?","TWN":"阿姨你呢？這裡有你認識的花嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아니. 하나도 모르겠군.","JPN":"いや、知らないな。","ENG":"No. Not a single one.","TWN":"沒有。一朵也不認識。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"전부 본 적 없는 것들이야.","JPN":"全部見たことのないものだ。","ENG":"I've never seen any of them before.","TWN":"都是沒見過的東西。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"크흠… 동월아, 서연아. 이 돈으로 저기서 아이스크림 먹고 올래?","JPN":"ゴホン……トウゲツ、シュエン。あそこのアイスめっちゃうまそうだけど、食べてみたくない？　ほら、お金！","ENG":"Ahem… Hey, kids. How about using this money to get some ice cream over there?","TWN":"咳…佟月，書妍，用這些錢去那邊吃冰淇淋好嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"먹을래요!","JPN":"食べたいです！","ENG":"Yes, please!","TWN":"好！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"다녀오겠습니다!","JPN":"行ってきます！","ENG":"We'll be back!","TWN":"我們去去就回！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 벚꽃 좀 봐. 저렇게 예쁜데 일 년에 보름 밖에 볼 수 없다니.","JPN":"見て、あの桜の花。あんなに綺麗なのに、1年に2週間ぐらいしか見れないなんて。","ENG":"Look at those cherry blossoms. They're so beautiful, but you only get to see them for two weeks a year.","TWN":"你看那櫻花。這麼漂亮卻一年只能看到半個月。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아쉽지 않아?","JPN":"もったいなくない？","ENG":"Isn't that kind of sad?","TWN":"不可惜嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래.","JPN":"……そうだな。","ENG":"…Yeah.","TWN":"…是啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국 사람들은 대단해. 차원함선이니 기상조절장치니, 그런 엄청난 발명품을 당연한 것처럼 뚝딱 만들어내잖아.","JPN":"管理局の人ってすごいよね。次元艦船とか気象調節装置とか、そんなすごい発明品を当たり前のようにポンポン生み出して。","ENG":"The people at the Administration really are something. Dimensional ships, Weather Control Systems… They just whip up all these amazing inventions like it's nothing.","TWN":"管理局的人真厲害。次元艦船、氣象調節裝置，他們輕易就發明出這些驚人的東西。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서연이가 저렇게 뛰어놀 수 있게 된 건, 네 덕분이다.","JPN":"シュエンがああやって走れるようになったのは、お前のおかげだ。","ENG":"Seoyeon being able to run around like that… it's thanks to you.","TWN":"書妍能這樣自由地奔跑，都是你的功勞。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…네가 만드는 발명품도 관리국 못지 않게 대단한 것들이야.","JPN":"……お前が作る発明品も、管理局に負けないほどすごいものだよ。","ENG":"…The stuff you invent is just as incredible as anything the Administration puts out.","TWN":"…你發明的東西也和管理局一樣厲害。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아하하, 웬일로 안 하던 칭찬을 하고 그런대? 갑자기 어디 떠나려고 그러나?","JPN":"あはは、おばあさんに褒められるなんて珍しい！　急にどっか行っちゃうんじゃないよね？","ENG":"Ahaha, a compliment coming from you? Are you planning to leave or something?","TWN":"哈哈哈，難得稱讚我呢？你突然是要去哪裡嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇게 됐다.","JPN":"そういうことだ。","ENG":"Yeah. I am.","TWN":"是啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"진짜…? 리얼?","JPN":"え……？　マジで？","ENG":"Wait, seriously…? For real?","TWN":"真的？是真的嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"여기보다 돈 많이 준대? 사기꾼한테 당한 건 아니지?","JPN":"ここより給料高かった？　詐欺とかじゃないよね？","ENG":"They're offering more money? Or did you get scammed?","TWN":"有給更多錢嗎？你沒有被騙吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돈 때문은 아니야. 사기를 당한 것도 아니고.","JPN":"金のためではない。詐欺でもないし。","ENG":"It's not about the money. And I didn't get scammed.","TWN":"不是因為錢。也沒有被騙。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으음… 뭐, 어르신이 속고 그냥 넘어갈 사람은 아니니까. 내가 걱정할 일은 아니려나.","JPN":"うーん……まあ、おばあさんは騙されてもやられっぱなしの人じゃないから。心配しなくていいか。","ENG":"Hmm… Well, it's not like you're the type to get fooled easily. I guess I don't need to worry.","TWN":"嗯…不過，你也不是會輕易被騙的人。應該不用我擔心。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이런 식으로 통보하게 돼서 미안하군.","JPN":"一方的に告げる形になって悪いな。","ENG":"Sorry for dropping this on you out of nowhere.","TWN":"這樣通知你，很抱歉。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"됐어. 인재를 붙잡아두지 못하는 건 사장이 부족한 탓이지 직원 잘못은 아니잖아.","JPN":"いいよ。人材を引き留められないのは社長の不徳で、社員は悪くないから。","ENG":"It's fine. If I can't hold on to a talented individual like you, that's on me as a boss. It's not your fault.","TWN":"沒關係。留不住人才，是老闆的不足，不是員工的錯。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"마지막으로 다 같이 좋은 추억이라도 만들어서 다행이네.","JPN":"最後にみんなでいい思い出が作れてよかったね。","ENG":"At least we got to make a nice final memory together.","TWN":"還好最後大家一起創造了美好的回憶。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"있지. 실은 나도 얼마 전에 관리국에서 스카웃 제의가 왔어.","JPN":"ねえ。実は私も、この前管理局からスカウトの提案を受けたの。","ENG":"Hey, you know, the Administration tried to scout me too not long ago.","TWN":"對了。其實我前陣子也收到了管理局的招募邀請。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관리국에서…?","JPN":"管理局から……？","ENG":"They did…?","TWN":"管理局？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"말은 안 했는데, 우리가 그 수상한 의뢰를 다녀온 뒤부터 어떤 변화가 생겼어.","JPN":"黙っていたけど、あの怪しい依頼から帰った後から、ちょっと妙なことがあって。","ENG":"Yeah. I didn't tell you but things started getting weird after we finished that shady job.","TWN":"我沒有說，但自從我們去過那個可疑的委託後，發生了一些變化。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"꿈에 웬 아저씨가 나오더라고.","JPN":"夢に知らないおじさんが出てきたの。","ENG":"This guy started showing up in my dreams.","TWN":"我夢到一個大叔。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아저씨…?","JPN":"おじさん……？","ENG":"A guy…?","TWN":"大叔…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"도포차림에 수염이 덥수룩한 그 남자였나?","JPN":"道着を着て、髭の生えた男だったか？","ENG":"Was it that man in a robe with a scruffy beard?","TWN":"是穿著道袍，留著鬍子的那個男人嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그건 아니지만, 옛날 사람 같은 말투를 쓰는 괴짜였어.","JPN":"そうじゃないけど、なんだか古風な喋り方の変人だった。","ENG":"No, but he talked like someone from way back. Total weirdo.","TWN":"不是，但是個說話方式像古人的怪人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"딱히 내 타입은 아니지만, 왠지 모르게 정겹더라. 꼭 오래 전부터 알고 지내던 사이처럼.","JPN":"別にタイプじゃないけど、どこか懐かしくて。まるでずっと前からの知り合いみたいに。","ENG":"Not really my type, but for some reason, he felt familiar. Like someone I've known for a long time.","TWN":"雖然不是我的菜，但不知為何很親切。就像很久以前就認識一樣。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런데 관리국에서 찾아온 사람이 어떤 검을 보여주더라.","JPN":"そんな中でだよ。管理局からやってきた人が、剣を1本見せてくれたの。","ENG":"And then this person from the Administration showed me a sword.","TWN":"然後管理局來找我的人，給我看了一把劍。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"깜짝 놀랐어. 꿈에서 본 사람도 그거랑 똑같은 걸 갖고 있었거든.","JPN":"びっくりした。夢で見た人も、あれと同じ剣を持っていたから。","ENG":"I was stunned. It was exactly like the one the guy in my dream had.","TWN":"我嚇了一跳。夢裡的那個人也拿著一模一樣的劍。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래서, 그 남자를 찾기 위해 관리국을 돕기로 했나?","JPN":"……それで、その男を探すために管理局に協力することにしたのか？","ENG":"…So, what? You're helping them just to find that man?","TWN":"…所以，你為了找那個男人，決定幫助管理局嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"에이, 그럴 리가.","JPN":"いや、そんなわけないでしょう。","ENG":"Pfft, as if.","TWN":"哎呀，怎麼可能。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이름도 모르는 사람을 찾자고, 나까지 보육원 애들을 두고 떠날 순 없잖아.","JPN":"名前も知らない人を探すために、私まで子どもたちをおいていくわけにはいかないよ。","ENG":"I'm not about to ditch the orphanage kids just to go look for some guy whose name I don't even know.","TWN":"為了找一個不知名的人，我怎麼能丟下育幼院的孩子們。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어차피 내가 쫓지 않아도… 언젠간 만날 것 같다는 느낌이 들거든.","JPN":"それに、どうせ私が探さなくても……いつかは会える気がするんだ。","ENG":"Besides, I've got a feeling… I'll run into him eventually. Even if I don't go looking.","TWN":"反正就算我不去追…我也覺得有一天會見到他。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"마치 운명처럼?","JPN":"まるで運命みたいにか？","ENG":"Like fate, huh?","TWN":"就像命運一樣？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응… 마치 운명처럼.","JPN":"うん……まるで運命みたいに。","ENG":"Yeah…. Like fate.","TWN":"嗯…就像命運一樣。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"언니! 내가 아이스크림 사왔어요!","JPN":"お姉さん！　アイス買って来たよ！","ENG":"Andy! I'm back with the ice cream!","TWN":"姊姊！我買冰淇淋回來了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"서연아, 그러다 넘어진다니까!","JPN":"シュエン、そんなに走ったら転ぶって！","ENG":"Seoyeon, you're gonna trip if you run like that!","TWN":"書妍，你跑慢一點，會跌倒的！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"와아, 동월이보다 빨리 온 거야? 달리는 것도 이제 능숙한데?","JPN":"わあ、トウゲツよりも早く着いたの？　もう走るのも板についてきたね！","ENG":"Whoa, did you beat Dongwol here? You're getting fast!","TWN":"哇，你比佟月還要快嗎？現在跑步也很熟練了呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"헤헤- 그럼요! 이제 안 넘어진…","JPN":"えへへ、そうだよ！　もう転ばな……","ENG":"Hehe, of course! I don't fall anymore–","TWN":"嘿嘿～當然！現在不會跌倒了…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 서연아!","JPN":"あっ、シュエン！","ENG":"Ah! Seoyeon!","TWN":"啊，書妍！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"와앗, 괜찮아?!","JPN":"わあっ、大丈夫！？","ENG":"Whoa! Are you okay?!","TWN":"哇啊，沒事吧？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"에헤헤… 실수했다.","JPN":"えへへ……ミスしちゃった。","ENG":"Ehehe… I messed up.","TWN":"嘿嘿…搞砸了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"그래도 이 언니가 잡아줬어.","JPN":"でも、このお姉さんが捕まえてくれたの。","ENG":"But this lady caught me.","TWN":"還好這位姊姊扶住我了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_QM_NULL","text":{"KOREA":"괜찮니? 다음부턴 조심하렴.","JPN":"大丈夫？　これからは気をつけなさいね。","ENG":"Are you all right? Be more careful next time.","TWN":"你沒事吧？下次要小心喔。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"응! 다음부턴 안 넘어지게 조심할게요!","JPN":"うん！　転ばないように気をつけます！","ENG":"Okay! I'll be more careful from now on!","TWN":"嗯！下次我會小心，不會再跌倒了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기, 고맙습니다. 다음부턴 저희가 잘 챙길게요.","JPN":"あの、ありがとうございます。ちゃんと注意します。","ENG":"Thank you so much. We'll keep a closer eye on her.","TWN":"那個，謝謝你。下次我們會照顧好她的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_QM_NULL","text":{"KOREA":"후후, 귀여운 아이들이랑 놀러나오셨군요.","JPN":"ふふ、可愛い子どもたちとおでかけのようですね。","ENG":"Hehe, out enjoying the day with some adorable kids, I see.","TWN":"呵呵，你們是帶著可愛的孩子們出來玩嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_QM_NULL","text":{"KOREA":"그럼, 즐거운 꽃구경 되시길.","JPN":"では、お花見楽しんでくださいね。","ENG":"Well then, I hope you all enjoy the flowers.","TWN":"那麼，祝你們賞花愉快。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"엄청 예쁜 언니다. 그치?","JPN":"すっごくきれいなお姉さんだね。","ENG":"She was really pretty, wasn't she?","TWN":"好漂亮的姊姊。對吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러게. 복장을 봐선 도시관리국 쪽 사람이려나?","JPN":"そうだね。服装からすると、都市管理局の人なのかな？","ENG":"Yeah. Judging by her outfit, maybe she's someone from City Management?","TWN":"是啊。看她的服裝，應該是城市管理局的人吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"방금 그 목소리… 어디선가…","JPN":"今の声……どこかで……","ENG":"That voice… It was–","TWN":"剛才那個聲音…好像在哪裡聽過…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_QM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"앗, 불꽃놀이 시작됐다.","JPN":"あっ、花火始まった。","ENG":"Whoa, fireworks!","TWN":"啊，煙火開始了。"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러네. 하늘에도 꽃이 피는 것 같아.","JPN":"本当だ。お空にもお花が咲いたみたい。","ENG":"Yeah! Looks like flowers are blooming in the sky now.","TWN":"是啊。感覺天空也開花了。"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYEON_NPC_GIRL_14","text":{"KOREA":"와아- 정말 예쁘다.","JPN":"わあ、本当にきれい。","ENG":"Wow…! So pretty!","TWN":"哇—真的好漂亮。"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"여기 계셨군요. 많이 바쁘신 줄 알았습니다.","JPN":"ここにいらっしゃいましたか。ご多忙かと思いましたが。","ENG":"There you are. I thought you'd be busy.","TWN":"原來你在這裡。我以為你很忙。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노스텔지어 공방에 온 도시 사람들이 볼 수 있는 특제 폭죽을 주문했거든. 이런 멋진 구경거리를 놓칠 순 없지.","JPN":"工房ノスタルジアに、街中の人々が見られる特製の花火を頼んだのでね。これほど素晴らしい光景を見逃す手はないさ。","ENG":"I placed an order with Nostalgia Workshop for fireworks the whole city can see. It’s not something you'd want to miss.","TWN":"我訂了特製煙火，讓所有來懷舊工坊的城市居民都能看到。不能錯過這麼棒的景象。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 오늘은 도시에 사계절이 돌아온 기념비적인 날이기도 하잖나.","JPN":"その上、今日は都市が四季を取り戻した記念すべき日でもあるからな。","ENG":"It's a historic day, after all. The seasons have finally returned to the city.","TWN":"而且今天也是城市迎來四季輪迴的紀念日。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…기상조절장치가 가져올 파급력은 그리 작지 않을 겁니다.","JPN":"……気象調節装置がもたらす影響は、決して小さくないでしょう。","ENG":"…The impact of this Weather Control System won't be small.","TWN":"…氣象調節裝置帶來的影響不小。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 장치는 언젠가 돌아올 사람을 위한 연결고리일세.","JPN":"この装置は、いつか戻ってくる者のための繋がりだ。","ENG":"This device is a bridge. For the one we're waiting for to find their way back.","TWN":"這個裝置是為了某天會回來的人，所留下的連結。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 파급이 두려웠다면, 난 애당초 아무것도 시작하지 못했겠지.","JPN":"影響を恐れたら、そもそも私は何も始められなかっただろう。","ENG":"If I'd been afraid of the consequences, I'd never have started any of this.","TWN":"如果害怕那些影響，我從一開始就什麼都做不了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그 이상이 실현된다면 분명 아름다운 재회가 되겠죠.","JPN":"その理想が実現すれば、きっと美しい再会になるでしょうね。","ENG":"If your vision comes true, it'll be a beautiful reunion.","TWN":"如果那個理想實現了，那會是個美好的重逢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"하지만 관리자님은 아름다운 결말이 아닌 이상적인 결말을 좇는 사람입니다. 원하는 인과를 얻기 위해선 뻔히 알고 있는 참상을 방조할 정도로요.","JPN":"しかし最高管理者は美しい結末ではなく、理想的な結末を追う人間です。望む因果のためなら、予見している惨状を傍観できるほどの。","ENG":"But you're not someone who chases beautiful endings. You aim for the ideal ones. Even if it means turning a blind eye to tragedy to get your desired causality.","TWN":"但管理者你是追求理想結局，而非美好結局的人。為了得到想要的因果，甚至會放任明知會發生的慘劇。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자는 세상에 두 개의 왜성이 강림할 줄 알면서도 막으려 하지 않았다… 그 말이 하고 싶은 건가?","JPN":"最高管理者はこの世に2つの矮星が降臨するだろうと知っていながらも、それを止めようとはしなかった……そう言いたいのか？","ENG":"Are you saying the Supreme Administrator knew two dwarf stars would descend upon the world… and still chose not to stop it?","TWN":"最高管理者明知會有兩顆矮星降臨，卻不試圖阻止…你是想說這個嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"관리자님이 제게 남겨둔 감정이 언젠가 후환으로 작용하게 될 겁니다.","JPN":"最高管理者がわたくしに残した感情は、いつか憂いを招く要因になるでしょう。","ENG":"The feelings you left behind in me will come back to haunt you someday.","TWN":"管理者留給我的情感，有朝一日會成為後患。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"관리자님이라면 이 또한 충분히 예상하고 있겠죠.","JPN":"最高管理者ならそれも十分予想しているでしょうが。","ENG":"And I'm sure you already expected that.","TWN":"管理者想必也預料到了吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 그렇게 되겠지. 하지만 자네도 알고 있잖나.","JPN":"おそらくそうなるだろうな。しかし君も分かっているではないか。","ENG":"Perhaps. But you know as well as I do.","TWN":"或許吧。但你也知道。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…세상에 불필요한 인과는 없다는걸.","JPN":"……この世に不要な因果などないということを。","ENG":"…There's no such thing as an unnecessary causality.","TWN":"…世上沒有不必要的因果。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…기계보다도 더 기계 같군요. 당신이란 사람은.","JPN":"……機械よりも機械のような人間ですね、あなたは。","ENG":"…You're more like a machine than an actual machine would ever be, you know that?","TWN":"…你這個人比機器還像機器。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 품기로 한 사사로운 마음은 용서를 구하지 않는 것 뿐일세.","JPN":"私が一つ、心に決めたことがあるとすれば、それは、許しを請わないということだ。","ENG":"The feelings I choose to carry, I won't ask forgiveness for them.","TWN":"我所懷抱的私人情感，是無需請求寬恕的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그 각오, 끝까지 변치 않으시길 바랍니다.","JPN":"その覚悟、最後まで変わらないことを願っています。","ENG":"Then I hope you stay true to that resolve. To the very end.","TWN":"希望你的決心，直到最後都不要改變。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아름다운 재회라… 나도 그랬으면 좋겠군.","JPN":"美しい再会か……そうなるといいんだが。","ENG":"A beautiful reunion… I'd like that too.","TWN":"美好的重逢啊…我也希望如此。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 기적이 일어난다고 한들, 두 사람은 끝내 엇갈리고 말겠지.","JPN":"しかし奇跡が起きたとしても、2人は結局すれ違うことになるだろう。","ENG":"But even if a miracle happens, those two are bound to go awry again.","TWN":"但就算奇蹟發生，那兩個人最終還是會錯過。"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"운명이란 건, 그 누구도 기다려주지 않으니 말이야.","JPN":"運命は、人を待ってはくれないからな。","ENG":"Because fate waits for no one.","TWN":"因為命運，不會等待任何人。"},"stage":{"bg":"EV_SUMMER_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};